// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int max_xor(int N, int K) {
    int max_xor = 0;
    int count = 0;
    int* S = (int*)malloc(K * sizeof(int));
    for (int i = 0; i < K; i++) {
        S[i] = (1 << i);
    }
    // Iterate over all possible combinations of elements from S
    for (int i = 0; i < (1 << K); i++) {
        int xor = 0;
        for (int j = 0; j < K; j++) {
            if ((i & (1 << j)) != 0) {
                xor ^= S[j];
            }
        }
        if (xor > max_xor) {
            max_xor = xor;
            count = 1;
        } else if (xor == max_xor) {
            count++;
        }
    }
    free(S);
    return (max_xor % MOD) * (count % MOD);
}

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int N, K;
        scanf("%d %d", &N, &K);
        printf("%d %d\n", max_xor(N, K), 1);
    }
    return 0;
}

